import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  LayoutDashboard, Users, Megaphone, FileText,
  Phone, Settings, LogOut, MessageSquare,
  ChevronLeft, ChevronRight, Shield, Menu
} from 'lucide-react';

const NAV_ITEMS = [
  { path: '/dashboard', icon: LayoutDashboard, label: 'Dashboard' },
  { path: '/contacts',  icon: Users,           label: 'Contacts'  },
  { path: '/campaigns', icon: Megaphone,        label: 'Campaigns' },
  { path: '/templates', icon: FileText,         label: 'Templates' },
  { path: '/senders',   icon: Phone,            label: 'Senders'   },
];

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const [collapsed, setCollapsed] = useState(false);
  const location = useLocation();

  const pageTitles = {
    '/dashboard': 'Dashboard',
    '/contacts':  'Contacts',
    '/campaigns': 'Campaigns',
    '/templates': 'Templates',
    '/senders':   'Sender Numbers',
    '/settings':  'Settings',
    '/admin':     'Admin Panel',
  };

  const currentTitle = Object.entries(pageTitles).find(([path]) =>
    location.pathname.startsWith(path)
  )?.[1] || 'SMS Marketing';

  const sidebarW = collapsed ? '72px' : '248px';

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#f8fafc' }}>

      {/* ── Sidebar ─────────────────────────────── */}
      <aside style={{
        width: sidebarW, flexShrink: 0,
        background: 'linear-gradient(180deg, #0f172a 0%, #1a2744 100%)',
        display: 'flex', flexDirection: 'column',
        position: 'fixed', top: 0, left: 0, height: '100vh',
        zIndex: 100, transition: 'width 0.25s ease', overflow: 'hidden',
        boxShadow: '4px 0 20px rgba(0,0,0,0.15)',
      }}>

        {/* Logo */}
        <div style={{
          padding: collapsed ? '18px 14px' : '18px 20px',
          borderBottom: '1px solid rgba(255,255,255,0.07)',
          display: 'flex', alignItems: 'center', gap: '12px',
          minHeight: '64px',
        }}>
          <div style={{
            width: '36px', height: '36px', borderRadius: '10px', flexShrink: 0,
            background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0 4px 12px rgba(99,102,241,0.4)',
          }}>
            <MessageSquare size={18} color="white" />
          </div>
          {!collapsed && (
            <div style={{ overflow: 'hidden' }}>
              <div style={{ color: 'white', fontWeight: 700, fontSize: '14px', whiteSpace: 'nowrap' }}>
                SMS Marketing
              </div>
              <div style={{ color: '#475569', fontSize: '11px', whiteSpace: 'nowrap' }}>
                Twilio Powered
              </div>
            </div>
          )}
        </div>

        {/* Nav */}
        <nav style={{ flex: 1, padding: '12px 8px', overflowY: 'auto', overflowX: 'hidden' }}>
          {!collapsed && (
            <div style={{ color: '#334155', fontSize: '10px', fontWeight: 700, letterSpacing: '0.08em', padding: '4px 10px 8px', textTransform: 'uppercase' }}>
              Main Menu
            </div>
          )}
          {NAV_ITEMS.map(({ path, icon: Icon, label }) => (
            <NavLink key={path} to={path} style={({ isActive }) => ({
              display: 'flex', alignItems: 'center',
              gap: collapsed ? 0 : '10px',
              justifyContent: collapsed ? 'center' : 'flex-start',
              padding: collapsed ? '10px' : '9px 12px',
              borderRadius: '8px', marginBottom: '3px',
              textDecoration: 'none',
              color: isActive ? 'white' : '#64748b',
              background: isActive ? 'rgba(99,102,241,0.25)' : 'transparent',
              borderLeft: isActive ? '3px solid #6366f1' : '3px solid transparent',
              fontWeight: isActive ? 600 : 400, fontSize: '13px',
              transition: 'all 0.15s',
              position: 'relative',
            })}>
              <Icon size={17} style={{ flexShrink: 0 }} />
              {!collapsed && <span style={{ whiteSpace: 'nowrap' }}>{label}</span>}
              {collapsed && (
                <span style={{
                  position: 'absolute', left: '110%', background: '#1e293b',
                  color: 'white', padding: '5px 10px', borderRadius: '6px',
                  fontSize: '12px', whiteSpace: 'nowrap', opacity: 0, pointerEvents: 'none',
                  border: '1px solid rgba(255,255,255,0.1)',
                  // Show on hover via CSS would need styled-components; skip for now
                }}>
                  {label}
                </span>
              )}
            </NavLink>
          ))}

          {/* Admin + Settings */}
          <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', marginTop: '10px', paddingTop: '10px' }}>
            {!collapsed && (
              <div style={{ color: '#334155', fontSize: '10px', fontWeight: 700, letterSpacing: '0.08em', padding: '4px 10px 8px', textTransform: 'uppercase' }}>
                Account
              </div>
            )}

            <NavLink to="/settings" style={({ isActive }) => ({
              display: 'flex', alignItems: 'center',
              gap: collapsed ? 0 : '10px',
              justifyContent: collapsed ? 'center' : 'flex-start',
              padding: collapsed ? '10px' : '9px 12px',
              borderRadius: '8px', marginBottom: '3px',
              textDecoration: 'none',
              color: isActive ? 'white' : '#64748b',
              background: isActive ? 'rgba(99,102,241,0.25)' : 'transparent',
              borderLeft: isActive ? '3px solid #6366f1' : '3px solid transparent',
              fontWeight: isActive ? 600 : 400, fontSize: '13px',
            })}>
              <Settings size={17} style={{ flexShrink: 0 }} />
              {!collapsed && <span>Settings</span>}
            </NavLink>

            {isAdmin && (
              <NavLink to="/admin" style={({ isActive }) => ({
                display: 'flex', alignItems: 'center',
                gap: collapsed ? 0 : '10px',
                justifyContent: collapsed ? 'center' : 'flex-start',
                padding: collapsed ? '10px' : '9px 12px',
                borderRadius: '8px',
                textDecoration: 'none',
                color: isActive ? 'white' : '#64748b',
                background: isActive ? 'rgba(99,102,241,0.25)' : 'transparent',
                borderLeft: isActive ? '3px solid #6366f1' : '3px solid transparent',
                fontWeight: isActive ? 600 : 400, fontSize: '13px',
              })}>
                <Shield size={17} style={{ flexShrink: 0 }} />
                {!collapsed && <span>Admin</span>}
              </NavLink>
            )}
          </div>
        </nav>

        {/* User */}
        <div style={{
          padding: collapsed ? '12px 8px' : '12px 14px',
          borderTop: '1px solid rgba(255,255,255,0.07)',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', justifyContent: collapsed ? 'center' : 'flex-start' }}>
            <div style={{
              width: '34px', height: '34px', borderRadius: '50%', flexShrink: 0,
              background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              color: 'white', fontWeight: 700, fontSize: '13px',
            }}>
              {user?.name?.charAt(0).toUpperCase()}
            </div>
            {!collapsed && (
              <>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ color: 'white', fontSize: '12px', fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {user?.name}
                  </div>
                  <div style={{ color: '#475569', fontSize: '10px', textTransform: 'capitalize' }}>
                    {user?.role}
                  </div>
                </div>
                <button onClick={logout} title="Logout" style={{
                  background: 'none', border: 'none', cursor: 'pointer',
                  color: '#475569', padding: '4px', borderRadius: '5px',
                  transition: 'color 0.15s',
                }}>
                  <LogOut size={15} />
                </button>
              </>
            )}
          </div>
        </div>

        {/* Collapse toggle */}
        <button onClick={() => setCollapsed(!collapsed)} style={{
          position: 'absolute', top: '22px', right: '-11px',
          width: '22px', height: '22px', borderRadius: '50%',
          background: '#1e293b', border: '2px solid #0f172a',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          cursor: 'pointer', color: 'white', zIndex: 10,
        }}>
          {collapsed ? <ChevronRight size={11} /> : <ChevronLeft size={11} />}
        </button>
      </aside>

      {/* ── Main Area ─────────────────────────── */}
      <div style={{ flex: 1, marginLeft: sidebarW, transition: 'margin-left 0.25s ease', display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>

        {/* Topbar */}
        <header style={{
          height: '56px', background: 'white', borderBottom: '1px solid #f1f5f9',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '0 28px', position: 'sticky', top: 0, zIndex: 50,
          boxShadow: '0 1px 3px rgba(0,0,0,0.04)',
        }}>
          <h2 style={{ fontSize: '16px', fontWeight: 700, color: '#0f172a' }}>
            {currentTitle}
          </h2>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <div style={{ fontSize: '12px', color: '#94a3b8' }}>
              {new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
            </div>
            <div style={{
              width: '32px', height: '32px', borderRadius: '50%',
              background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              color: 'white', fontWeight: 700, fontSize: '12px', cursor: 'pointer',
            }}
              onClick={() => window.location.href = '/settings'}
              title="Go to Settings"
            >
              {user?.name?.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        {/* Page content */}
        <main style={{ flex: 1 }}>
          <Outlet />
        </main>
      </div>
    </div>
  );
}
